final class AppState: ObservableObject {
    @Published var authToken: String = "demo-auth-token"
    @Published var portfolio = Portfolio(cashBalance: 100_000, positions: [])
    @Published var watchlist: [String] = ["AAPL", "MSFT", "TSLA", "NVDA", "AMZN"]
    @Published var quotes: [String: Quote] = [:]
    @Published var orders: [TradeOrder] = []
    @Published var activities: [TradeActivity] = []
    @Published var selectedSymbol: String = "AAPL"
    @Published var isConnected: Bool = false
    @Published var lastError: String?

    let api = APIClient()
    let marketStream = MarketDataStream()

    private var cancellables = Set<AnyCancellable>()

    init() {
        bindStream()
        loadInitialQuotes()
    }

    private func bindStream() {
        marketStream.$quotes
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                self?.quotes = quotes
            }
            .store(in: &cancellables)

        marketStream.$isConnected
            .receive(on: DispatchQueue.main)
            .sink { [weak self] connected in
                self?.isConnected = connected
            }
            .store(in: &cancellables)
    }

    func startStreaming() {
        marketStream.connect(symbols: watchlist)
    }

    func stopStreaming() {
        marketStream.disconnect()
    }

    func loadInitialQuotes() {
        let seed: [Quote] = [
            Quote(symbol: "AAPL", price: 189.22, change: 1.21, changePercent: 0.64, bid: 189.20, ask: 189.24, volume: 21_000_000, timestamp: Date()),
            Quote(symbol: "MSFT", price: 421.45, change: -0.82, changePercent: -0.19, bid: 421.40, ask: 421.48, volume: 15_400_000, timestamp: Date()),
            Quote(symbol: "TSLA", price: 174.88, change: 2.15, changePercent: 1.25, bid: 174.84, ask: 174.90, volume: 33_200_000, timestamp: Date()),
            Quote(symbol: "NVDA", price: 912.10, change: 8.93, changePercent: 0.99, bid: 912.00, ask: 912.20, volume: 26_500_000, timestamp: Date()),
            Quote(symbol: "AMZN", price: 182.14, change: -1.04, changePercent: -0.57, bid: 182.10, ask: 182.18, volume: 18_300_000, timestamp: Date())
        ]
        quotes = Dictionary(uniqueKeysWithValues: seed.map { ($0.symbol, $0) })
    }

    func executeOrder(symbol: String, side: OrderSide, quantity: Int, type: OrderType) {
        guard quantity > 0 else {
            lastError = "Quantity must be greater than zero."
            return
        }

        guard let quote = quotes[symbol] else {
            lastError = "Market data unavailable."
            return
        }

        let executionPrice = side == .buy ? quote.ask : quote.bid
        let estimatedValue = executionPrice * Double(quantity)

        if side == .buy && portfolio.cashBalance < estimatedValue {
            lastError = "Insufficient buying power."
            return
        }

        let order = TradeOrder(
            id: UUID(),
            symbol: symbol,
            side: side,
            quantity: quantity,
            type: type,
            status: .pending,
            submittedAt: Date(),
            executionPrice: nil
        )

        orders.insert(order, at: 0)

        Task {
            do {
                let response = try await api.submitOrder(order: order, token: authToken)
                await MainActor.run {
                    self.applyExecution(orderID: order.id, fillPrice: response.fillPrice)
                }
            } catch {
                await MainActor.run {
                    self.failOrder(orderID: order.id, message: error.localizedDescription)
                }
            }
        }
    }

    @MainActor
    private func applyExecution(orderID: UUID, fillPrice: Double) {
        guard let index = orders.firstIndex(where: { $0.id == orderID }) else { return }
        var order = orders[index]
        order.status = .filled
        order.executionPrice = fillPrice
        orders[index] = order

        let tradeValue = fillPrice * Double(order.quantity)

        switch order.side {
        case .buy:
            portfolio.cashBalance -= tradeValue
            if let positionIndex = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                var position = portfolio.positions[positionIndex]
                let totalCost = (position.averageCost * Double(position.quantity)) + tradeValue
                let newQuantity = position.quantity + order.quantity
                position.quantity = newQuantity
                position.averageCost = totalCost / Double(newQuantity)
                portfolio.positions[positionIndex] = position
            } else {
                portfolio.positions.append(Position(symbol: order.symbol, quantity: order.quantity, averageCost: fillPrice))
            }
        case .sell:
            if let positionIndex = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                var position = portfolio.positions[positionIndex]
                let sellQuantity = min(order.quantity, position.quantity)
                portfolio.cashBalance += fillPrice * Double(sellQuantity)
                position.quantity -= sellQuantity
                if position.quantity == 0 {
                    portfolio.positions.remove(at: positionIndex)
                } else {
                    portfolio.positions[positionIndex] = position
                }
            }
        }

        activities.insert(
            TradeActivity(
                id: UUID(),
                title: "\(order.side.rawValue.capitalized) \(order.quantity) \(order.symbol)",
                detail: "Filled at \(fillPrice.currencyString)",
                timestamp: Date()
            ),
            at: 0
        )
    }

    @MainActor
    private func failOrder(orderID: UUID, message: String) {
        guard let index = orders.firstIndex(where: { $0.id == orderID }) else { return }
        var order = orders[index]
        order.status = .rejected
        orders[index] = order
        lastError = message
        activities.insert(
            TradeActivity(
                id: UUID(),
                title: "Order Rejected",
                detail: "\(order.symbol) \(order.quantity) shares",
                timestamp: Date()
            ),
            at: 0
        )
    }

    func marketValue(for position: Position) -> Double {
        let price = quotes[position.symbol]?.price ?? position.averageCost
        return price * Double(position.quantity)
    }

    func unrealizedPnL(for position: Position) -> Double {
        marketValue(for: position) - (position.averageCost * Double(position.quantity))
    }

    var totalPortfolioValue: Double {
        portfolio.cashBalance + portfolio.positions.reduce(0) { $0 + marketValue(for: $1) }
    }
}

