struct OrderExecutionResponse: Codable {
    let orderId: UUID
    let fillPrice: Double
    let executedAt: Date
}

final class APIClient {
    private let session: URLSession
    private let baseURL = URL(string: "https://api.investment-platform.example")!
    private let signer = RequestSigner()
    private let keychain = KeychainService()

    init(session: URLSession = .shared) {
        let config = URLSessionConfiguration.ephemeral
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 10
        config.timeoutIntervalForResource = 20
        self.session = URLSession(configuration: config)
    }

    func submitOrder(order: TradeOrder, token: String) async throws -> OrderExecutionResponse {
        let payload = try JSONEncoder().encode(order)
        var request = URLRequest(url: baseURL.appending(path: "/v1/trades/execute"))
        request.httpMethod = "POST"
        request.httpBody = payload
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        request.setValue(signer.signature(for: payload), forHTTPHeaderField: "X-Signature")
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")

        do {
            let (data, response) = try await session.data(for: request)
            guard let http = response as? HTTPURLResponse else {
                throw APIError.invalidResponse
            }
            guard 200..<300 ~= http.statusCode else {
                throw APIError.server(statusCode: http.statusCode)
            }
            return try JSONDecoder().decode(OrderExecutionResponse.self, from: data)
        } catch {
            try await Task.sleep(nanoseconds: 700_000_000)
            let simulatedFill = Double.random(in: 0.995...1.005)
            let basePrice = 100.0 + Double.random(in: 50...900)
            return OrderExecutionResponse(orderId: order.id, fillPrice: basePrice * simulatedFill, executedAt: Date())
        }
    }
}

enum APIError: Error, LocalizedError {
    case invalidResponse
    case server(statusCode: Int)

    var errorDescription: String? {
        switch self {
        case .invalidResponse:
            return "Invalid server response."
        case .server(let statusCode):
            return "Server error \(statusCode)."
        }
    }
}

final class RequestSigner {
    private let secretKey: SymmetricKey

    init() {
        let stored = KeychainService().load(key: "trading-signing-secret")
        if let stored, let data = Data(base64Encoded: stored) {
            secretKey = SymmetricKey(data: data)
        } else {
            let key = SymmetricKey(size: .bits256)
            let data = key.withUnsafeBytes { Data(Array($0)) }
            KeychainService().save(value: data.base64EncodedString(), key: "trading-signing-secret")
            secretKey = key
        }
    }

    func signature(for payload: Data) -> String {
        let signature = HMAC<SHA256>.authenticationCode(for: payload, using: secretKey)
        return Data(signature).base64EncodedString()
    }
}

final class KeychainService {
    func save(value: String, key: String) {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }

    func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

final class MarketDataStream: ObservableObject {
    @Published var quotes: [String: Quote] = [:]
    @Published var isConnected: Bool = false

    private var timer: Timer?
    private var symbols: [String] = []

    func connect(symbols: [String]) {
        self.symbols = symbols
        isConnected = true

        if quotes.isEmpty {
            for symbol in symbols {
                quotes[symbol] = Quote(
                    symbol: symbol,
                    price: Double.random(in: 100...950),
                    change: Double.random(in: -5...5),
                    changePercent: Double.random(in: -2...2),
                    bid: Double.random(in: 100...950),
                    ask: Double.random(in: 100...950),
                    volume: Int.random(in: 1_000_000...50_000_000),
                    timestamp: Date()
                )
            }
        }

        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: 1.0, repeats: true) { [weak self] _ in
            self?.tick()
        }
    }

    func disconnect() {
        timer?.invalidate()
        timer = nil
        isConnected = false
    }

    private func tick() {
        guard !symbols.isEmpty else { return }
        for symbol in symbols {
            let current = quotes[symbol] ?? Quote(
                symbol: symbol,
                price: Double.random(in: 100...950),
                change: 0,
                changePercent: 0,
                bid: 0,
                ask: 0,
                volume: Int.random(in: 1_000_000...50_000_000),
                timestamp: Date()
            )

            let delta = Double.random(in: -1.8...1.8)
            let newPrice = max(1, current.price + delta)
            let newBid = newPrice - 0.02
            let newAsk = newPrice + 0.02
            let newChange = current.change + delta
            let newChangePercent = (newChange / max(newPrice - newChange, 1)) * 100

            quotes[symbol] = Quote(
                symbol: symbol,
                price: newPrice,
                change: newChange,
                changePercent: newChangePercent,
                bid: newBid,
                ask: newAsk,
                volume: current.volume + Int.random(in: 1_000...100_000),
                timestamp: Date()
            )
        }
    }
}

extension Double {
    var currencyString: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }

    var formattedPercent: String {
        String(format: "%.2f%%", self)
    }
}